512: absl::Status
513: ListenerManagerImpl::setupSocketFactoryForListener(ListenerImpl& new_listener,
514:                                                    const ListenerImpl& existing_listener) {
515:   bool same_socket_options = true;
516:   if (new_listener.reusePort() != existing_listener.reusePort()) {
517:     return absl::InvalidArgumentError(fmt::format(
518:         "Listener {}: reuse port cannot be changed during an update", new_listener.name()));
519:   }
520: 
521:   same_socket_options = existing_listener.socketOptionsEqual(new_listener);
522:   if (!same_socket_options && new_listener.reusePort() == false) {
523:     return absl::InvalidArgumentError(
524:         fmt::format("Listener {}: doesn't support update any socket options "
525:                     "when the reuse port isn't enabled",
526:                     new_listener.name()));
527:   }
528: 
529:   if (!(existing_listener.hasCompatibleAddress(new_listener) && same_socket_options)) {
530:     RETURN_IF_NOT_OK(setNewOrDrainingSocketFactory(new_listener.name(), new_listener));
531:   } else {
532:     RETURN_IF_NOT_OK(new_listener.cloneSocketFactoryFrom(existing_listener));
533:   }
534:   return absl::OkStatus();
535: }
