841: void ListenerManagerImpl::drainFilterChains(ListenerImplPtr&& draining_listener,
842:                                             ListenerImpl& new_listener) {
843:   // First add the listener to the draining list.
844:   std::list<DrainingFilterChainsManager>::iterator draining_group =
845:       draining_filter_chains_manager_.emplace(draining_filter_chains_manager_.begin(),
846:                                               std::move(draining_listener), workers_.size());
847:   draining_group->getDrainingListener().diffFilterChain(
848:       new_listener, [&draining_group](Network::DrainableFilterChain& filter_chain) mutable {
849:         filter_chain.startDraining();
850:         draining_group->addFilterChainToDrain(filter_chain);
851:       });
852:   auto filter_chain_size = draining_group->numDrainingFilterChains();
853:   stats_.total_filter_chains_draining_.add(filter_chain_size);
854:   draining_group->getDrainingListener().debugLog(
855:       absl::StrCat("draining ", filter_chain_size, " filter chains in listener ",
856:                    draining_group->getDrainingListener().name()));
857: 
858:   // Start the drain sequence which completes when the listener's drain manager has completed
859:   // draining at whatever the server configured drain times are.
860:   draining_group->startDrainSequence(
861:       server_.options().drainTime(), server_.dispatcher(), [this, draining_group]() -> void {
862:         draining_group->getDrainingListener().debugLog(
863:             absl::StrCat("removing draining filter chains from listener ",
864:                          draining_group->getDrainingListener().name()));
865:         for (const auto& worker : workers_) {
866:           // Once the drain time has completed via the drain manager's timer, we tell the workers
867:           // to remove the filter chains.
868:           worker->removeFilterChains(
869:               draining_group->getDrainingListenerTag(), draining_group->getDrainingFilterChains(),
870:               [this, draining_group]() -> void {
871:                 // The remove listener completion is called on the worker thread. We post back to
872:                 // the main thread to avoid locking. This makes sure that we don't destroy the
873:                 // listener while filters might still be using its context (stats, etc.).
874:                 server_.dispatcher().post([this, draining_group]() -> void {
875:                   if (draining_group->decWorkersPendingRemoval() == 0) {
876:                     draining_group->getDrainingListener().debugLog(
877:                         absl::StrCat("draining filter chains from listener ",
878:                                      draining_group->getDrainingListener().name(), " complete"));
879:                     stats_.total_filter_chains_draining_.sub(
880:                         draining_group->numDrainingFilterChains());
881:                     draining_filter_chains_manager_.erase(draining_group);
882:                   }
883:                 });
884:               });
885:         }
886:       });
887:   updateWarmingActiveGauges();
888: }
