377: ProtobufTypes::MessagePtr
378: ListenerManagerImpl::dumpListenerConfigs(const Matchers::StringMatcher& name_matcher) {
379:   auto config_dump = std::make_unique<envoy::admin::v3::ListenersConfigDump>();
380:   config_dump->set_version_info(lds_api_ != nullptr ? lds_api_->versionInfo() : "");
381: 
382:   using DynamicListener = envoy::admin::v3::ListenersConfigDump::DynamicListener;
383:   using DynamicListenerState = envoy::admin::v3::ListenersConfigDump::DynamicListenerState;
384:   absl::flat_hash_map<std::string, DynamicListener*> listener_map;
385: 
386:   for (const auto& listener : active_listeners_) {
387:     if (!name_matcher.match(listener->config().name())) {
388:       continue;
389:     }
390:     if (listener->blockRemove()) {
391:       auto& static_listener = *config_dump->mutable_static_listeners()->Add();
392:       static_listener.mutable_listener()->PackFrom(listener->config());
393:       TimestampUtil::systemClockToTimestamp(listener->last_updated_,
394:                                             *(static_listener.mutable_last_updated()));
395:       continue;
396:     }
397:     // Listeners are always added to active_listeners_ list before workers are started.
398:     // This applies even when the listeners are still waiting for initialization.
399:     // To avoid confusion in config dump, in that case, we add these listeners to warming
400:     // listeners config dump rather than active ones.
401:     DynamicListener* dynamic_listener =
402:         getOrCreateDynamicListener(listener->name(), *config_dump, listener_map);
403: 
404:     DynamicListenerState* dump_listener;
405:     if (workers_started_) {
406:       dump_listener = dynamic_listener->mutable_active_state();
407:     } else {
408:       dump_listener = dynamic_listener->mutable_warming_state();
409:     }
410:     fillState(*dump_listener, *listener);
411:   }
412: 
413:   for (const auto& listener : warming_listeners_) {
414:     if (!name_matcher.match(listener->config().name())) {
415:       continue;
416:     }
417:     DynamicListener* dynamic_listener =
418:         getOrCreateDynamicListener(listener->name(), *config_dump, listener_map);
419:     DynamicListenerState* dump_listener = dynamic_listener->mutable_warming_state();
420:     fillState(*dump_listener, *listener);
421:   }
422: 
423:   for (const auto& draining_listener : draining_listeners_) {
424:     if (!name_matcher.match(draining_listener.listener_->config().name())) {
425:       continue;
426:     }
427:     const auto& listener = draining_listener.listener_;
428:     DynamicListener* dynamic_listener =
429:         getOrCreateDynamicListener(listener->name(), *config_dump, listener_map);
430:     DynamicListenerState* dump_listener = dynamic_listener->mutable_draining_state();
431:     fillState(*dump_listener, *listener);
432:   }
433: 
434:   for (const auto& [error_name, error_state] : error_state_tracker_) {
435:     DynamicListener* dynamic_listener =
436:         getOrCreateDynamicListener(error_name, *config_dump, listener_map);
437: 
438:     const envoy::admin::v3::UpdateFailureState& state = *error_state;
439:     dynamic_listener->mutable_error_state()->CopyFrom(state);
440:   }
441: 
442:   // Dump errors not associated with named listeners.
443:   for (const auto& error : overall_error_state_) {
444:     config_dump->add_dynamic_listeners()->mutable_error_state()->CopyFrom(*error);
445:   }
446: 
447:   return config_dump;
448: }
