813: void ListenerManagerImpl::inPlaceFilterChainUpdate(ListenerImpl& listener) {
814:   auto existing_active_listener = getListenerByName(active_listeners_, listener.name());
815:   auto existing_warming_listener = getListenerByName(warming_listeners_, listener.name());
816:   ASSERT(existing_warming_listener != warming_listeners_.end());
817:   ASSERT(*existing_warming_listener != nullptr);
818: 
819:   (*existing_warming_listener)->debugLog("execute in place filter chain update");
820: 
821:   // Now that in place filter chain update was decided, the replaced listener must be in active
822:   // list. It requires stop/remove listener procedure cancelling the in placed update if any.
823:   ASSERT(existing_active_listener != active_listeners_.end());
824:   ASSERT(*existing_active_listener != nullptr);
825: 
826:   for (const auto& worker : workers_) {
827:     // Explicitly override the existing listener with a new listener config.
828:     addListenerToWorker(*worker, listener.listenerTag(), listener, nullptr);
829:   }
830: 
831:   auto previous_listener = std::move(*existing_active_listener);
832:   *existing_active_listener = std::move(*existing_warming_listener);
833:   // Finish active_listeners_ transformation before calling `drainFilterChains` as it depends on
834:   // their state.
835:   drainFilterChains(std::move(previous_listener), **existing_active_listener);
836: 
837:   warming_listeners_.erase(existing_warming_listener);
838:   updateWarmingActiveGauges();
839: }
