781: void ListenerManagerImpl::onListenerWarmed(ListenerImpl& listener) {
782:   // The warmed listener should be added first so that the worker will accept new connections
783:   // when it stops listening on the old listener.
784:   if (!doFinalPreWorkerListenerInit(listener)) {
785:     incListenerCreateFailureStat();
786:     // TODO(mattklein123): Technically we don't need to remove the active listener if one exists.
787:     // The following call will remove both.
788:     removeListenerInternal(listener.name(), true);
789:     return;
790:   }
791:   for (const auto& worker : workers_) {
792:     addListenerToWorker(*worker, absl::nullopt, listener, nullptr);
793:   }
794: 
795:   auto existing_active_listener = getListenerByName(active_listeners_, listener.name());
796:   auto existing_warming_listener = getListenerByName(warming_listeners_, listener.name());
797: 
798:   (*existing_warming_listener)->debugLog("warm complete. updating active listener");
799:   if (existing_active_listener != active_listeners_.end()) {
800:     // Finish active_listeners_ transformation before calling `drainListener` as it depends on their
801:     // state.
802:     auto listener = std::move(*existing_active_listener);
803:     *existing_active_listener = std::move(*existing_warming_listener);
804:     drainListener(std::move(listener));
805:   } else {
806:     active_listeners_.emplace_back(std::move(*existing_warming_listener));
807:   }
808: 
809:   warming_listeners_.erase(existing_warming_listener);
810:   updateWarmingActiveGauges();
811: }
