1191: absl::Status ListenerManagerImpl::createListenSocketFactory(ListenerImpl& listener) {
1192:   Network::Socket::Type socket_type = listener.socketType();
1193:   ListenerComponentFactory::BindType bind_type = ListenerComponentFactory::BindType::NoBind;
1194:   if (listener.bindToPort()) {
1195:     bind_type = listener.reusePort() ? ListenerComponentFactory::BindType::ReusePort
1196:                                      : ListenerComponentFactory::BindType::NoReusePort;
1197:   }
1198:   absl::Status socket_status = absl::OkStatus();
1199:   TRY_ASSERT_MAIN_THREAD {
1200:     Network::SocketCreationOptions creation_options;
1201:     creation_options.mptcp_enabled_ = listener.mptcpEnabled();
1202:     for (std::vector<Network::Address::InstanceConstSharedPtr>::size_type i = 0;
1203:          i < listener.addresses().size(); i++) {
1204:       auto factory_or_error = ListenSocketFactoryImpl::create(
1205:           *factory_, listener.addresses()[i], socket_type, listener.listenSocketOptions(i),
1206:           listener.name(), listener.tcpBacklogSize(), bind_type, creation_options,
1207:           server_.options().concurrency());
1208:       if (!factory_or_error.status().ok()) {
1209:         socket_status = factory_or_error.status();
1210:       } else {
1211:         socket_status = listener.addSocketFactory(std::move(*factory_or_error));
1212:       }
1213:       if (!socket_status.ok()) {
1214:         break;
1215:       }
1216:     }
1217:   }
1218:   END_TRY
1219:   CATCH(const EnvoyException& e, {
1220:     socket_status = absl::InvalidArgumentError(e.what());
1221:     ;
1222:   });
1223:   if (!socket_status.ok()) {
1224:     ENVOY_LOG(error, "listener '{}' failed to bind or apply socket options: {}", listener.name(),
1225:               socket_status.message());
1226:     incListenerCreateFailureStat();
1227:   }
1228:   return socket_status;
1229: }
