1002: void ListenerManagerImpl::stopListener(Network::ListenerConfig& listener,
1003:                                        const Network::ExtraShutdownListenerOptions& options,
1004:                                        std::function<void()> callback) {
1005:   const auto workers_pending_stop = std::make_shared<std::atomic<uint64_t>>(workers_.size());
1006:   for (const auto& worker : workers_) {
1007:     worker->stopListener(listener, options, [this, callback, workers_pending_stop]() {
1008:       if (--(*workers_pending_stop) == 0) {
1009:         server_.dispatcher().post(callback);
1010:       }
1011:     });
1012:   }
1013: }
1014: 
1015: void ListenerManagerImpl::stopListeners(StopListenersType stop_listeners_type,
1016:                                         const Network::ExtraShutdownListenerOptions& options) {
1017:   stop_listeners_type_ = stop_listeners_type;
1018:   for (Network::ListenerConfig& listener : listeners()) {
1019:     if (stop_listeners_type != StopListenersType::InboundOnly ||
1020:         listener.listenerInfo()->direction() == envoy::config::core::v3::INBOUND) {
1021:       ENVOY_LOG(debug, "begin stop listener: name={}", listener.name());
1022:       auto existing_warming_listener = getListenerByName(warming_listeners_, listener.name());
1023:       // Destroy a warming listener directly.
1024:       if (existing_warming_listener != warming_listeners_.end()) {
1025:         (*existing_warming_listener)->debugLog("removing warming listener");
1026:         warming_listeners_.erase(existing_warming_listener);
1027:       }
1028:       // Close the socket once all workers stopped accepting its connections.
1029:       // This allows clients to fast fail instead of waiting in the accept queue.
1030:       const uint64_t listener_tag = listener.listenerTag();
1031:       stopListener(listener, options, [this, listener_tag]() {
1032:         stats_.listener_stopped_.inc();
1033:         for (auto& listener : active_listeners_) {
1034:           if (listener->listenerTag() == listener_tag) {
1035:             maybeCloseSocketsForListener(*listener);
1036:           }
1037:         }
1038:       });
1039:     }
1040:   }
1041: }
1042: 
1043: void ListenerManagerImpl::stopWorkers() {
1044:   if (!workers_started_) {
1045:     return;
1046:   }
1047:   for (const auto& worker : workers_) {
1048:     worker->stop();
1049:   }
1050: }
