53: // Finds and returns the DynamicListener for the name provided from listener_map, creating and
54: // inserting one if necessary.
55: envoy::admin::v3::ListenersConfigDump::DynamicListener* getOrCreateDynamicListener(
56:     const std::string& name, envoy::admin::v3::ListenersConfigDump& dump,
57:     absl::flat_hash_map<std::string, envoy::admin::v3::ListenersConfigDump::DynamicListener*>&
58:         listener_map) {
