80: absl::StatusOr<Filter::NetworkFilterFactoriesList>
81: ProdListenerComponentFactory::createNetworkFilterFactoryListImpl(
82:     const Protobuf::RepeatedPtrField<envoy::config::listener::v3::Filter>& filters,
83:     Server::Configuration::FilterChainFactoryContext& filter_chain_factory_context,
84:     Filter::NetworkFilterConfigProviderManagerImpl& config_provider_manager) {
85:   Filter::NetworkFilterFactoriesList ret;
86:   ret.reserve(filters.size());
87:   for (ssize_t i = 0; i < filters.size(); i++) {
88:     const auto& proto_config = filters[i];
89:     const bool is_terminal = i == filters.size() - 1;
90:     ENVOY_LOG(debug, "  filter #{}:", i);
91: 
92:     if (proto_config.config_type_case() ==
93:         envoy::config::listener::v3::Filter::ConfigTypeCase::kConfigDiscovery) {
94:       ENVOY_LOG(debug, "      dynamic filter name: {}", proto_config.name());
95:       ret.push_back(config_provider_manager.createDynamicFilterConfigProvider(
96:           proto_config.config_discovery(), proto_config.name(),
97:           filter_chain_factory_context.serverFactoryContext(), filter_chain_factory_context,
98:           filter_chain_factory_context.serverFactoryContext().clusterManager(), is_terminal,
99:           "network", nullptr));
100:       continue;
101:     }
102: 
103:     ENVOY_LOG(debug, "    name: {}", proto_config.name());
104:     ENVOY_LOG(debug, "  config: {}",
105:               MessageUtil::convertToStringForLogs(
106:                   static_cast<const Protobuf::Message&>(proto_config.typed_config())));
107: 
108:     // Now see if there is a factory that will accept the config.
109:     auto& factory =
110:         Config::Utility::getAndCheckFactory<Configuration::NamedNetworkFilterConfigFactory>(
111:             proto_config);
112: 
113:     auto message = Config::Utility::translateToFactoryConfig(
114:         proto_config, filter_chain_factory_context.messageValidationVisitor(), factory);
115:     RETURN_IF_NOT_OK(Config::Utility::validateTerminalFilters(
116:         filters[i].name(), factory.name(), "network",
117:         factory.isTerminalFilterByProto(*message,
118:                                         filter_chain_factory_context.serverFactoryContext()),
119:         is_terminal));
120:     auto callback_or_error =
121:         factory.createFilterFactoryFromProto(*message, filter_chain_factory_context);
122:     RETURN_IF_NOT_OK(callback_or_error.status());
123:     ret.push_back(config_provider_manager.createStaticFilterConfigProvider(*callback_or_error,
124:                                                                            proto_config.name()));
125:   }
126:   return ret;
127: }
