282: absl::StatusOr<Network::SocketSharedPtr> ProdListenerComponentFactory::createListenSocket(
283:     Network::Address::InstanceConstSharedPtr address, Network::Socket::Type socket_type,
284:     const Network::Socket::OptionsSharedPtr& options, BindType bind_type,
285:     const Network::SocketCreationOptions& creation_options, uint32_t worker_index) {
286:   ASSERT(socket_type == Network::Socket::Type::Stream ||
287:          socket_type == Network::Socket::Type::Datagram);
288: 
289:   // First we try to get the socket from our parent if applicable in each case below.
290:   if (address->type() == Network::Address::Type::Pipe) {
291:     if (socket_type != Network::Socket::Type::Stream) {
292:       // This could be implemented in the future, since Unix domain sockets
293:       // support SOCK_DGRAM, but there would need to be a way to specify it in
294:       // envoy.api.v2.core.Pipe.
295:       return absl::InvalidArgumentError(
296:           fmt::format("socket type {} not supported for pipes", toString(socket_type)));
297:     }
298:     const std::string addr = fmt::format("unix://{}", address->asString());
299:     const int fd = server_.hotRestart().duplicateParentListenSocket(addr, worker_index);
300:     Network::IoHandlePtr io_handle = std::make_unique<Network::IoSocketHandleImpl>(fd);
301:     if (io_handle->isOpen()) {
302:       ENVOY_LOG(debug, "obtained socket for address {} from parent", addr);
303:       return std::make_shared<Network::UdsListenSocket>(std::move(io_handle), address);
304:     }
305:     return std::make_shared<Network::UdsListenSocket>(address);
306:   } else if (address->type() == Network::Address::Type::EnvoyInternal) {
307:     // Listener manager should have validated that envoy internal address doesn't work with udp
308:     // listener yet.
309:     ASSERT(socket_type == Network::Socket::Type::Stream);
310:     return std::make_shared<Network::InternalListenSocket>(address);
311:   }
312: 
313:   const std::string scheme = (socket_type == Network::Socket::Type::Stream)
314:                                  ? std::string(Network::Utility::TCP_SCHEME)
315:                                  : std::string(Network::Utility::UDP_SCHEME);
316:   const std::string addr = absl::StrCat(scheme, address->asString());
317: 
318:   if (bind_type != BindType::NoBind) {
319:     const int fd = server_.hotRestart().duplicateParentListenSocket(addr, worker_index);
320:     if (fd != -1) {
321:       ENVOY_LOG(debug, "obtained socket for address {} from parent", addr);
322:       Network::IoHandlePtr io_handle = std::make_unique<Network::IoSocketHandleImpl>(fd);
323:       if (socket_type == Network::Socket::Type::Stream) {
324:         return std::make_shared<Network::TcpListenSocket>(std::move(io_handle), address, options);
325:       } else {
326:         auto socket = std::make_shared<Network::UdpListenSocket>(
327:             std::move(io_handle), address, options,
328:             server_.hotRestart().parentDrainedCallbackRegistrar());
329:         return socket;
330:       }
331:     }
332:   }
333: 
334:   if (socket_type == Network::Socket::Type::Stream) {
335:     return std::make_shared<Network::TcpListenSocket>(
336:         address, options, bind_type != BindType::NoBind, creation_options);
337:   } else {
338:     return std::make_shared<Network::UdpListenSocket>(
339:         address, options, bind_type != BindType::NoBind, creation_options);
340:   }
341: }
