454: absl::StatusOr<bool>
455: ListenerManagerImpl::addOrUpdateListener(const envoy::config::listener::v3::Listener& config,
456:                                          const std::string& version_info, bool added_via_api) {
457:   std::string name;
458:   if (!config.name().empty()) {
459:     name = config.name();
460:   } else {
461:     // TODO (soulxu): The random uuid name is bad for logging. We can use listening addresses in
462:     // the log to improve that.
463:     name = server_.api().randomGenerator().uuid();
464:   }
465: 
466:   // TODO(junr03): currently only one ApiListener can be installed via bootstrap to avoid having to
467:   // build a collection of listeners, and to have to be able to warm and drain the listeners. In the
468:   // future allow multiple ApiListeners, and allow them to be created via LDS as well as bootstrap.
469:   if (config.has_api_listener()) {
470:     if (config.has_internal_listener()) {
471:       return absl::InvalidArgumentError(fmt::format(
472:           "error adding listener named '{}': api_listener and internal_listener cannot be both set",
473:           name));
474:     }
475:     if (!api_listener_ && !added_via_api) {
476:       auto listener_or_error = HttpApiListener::create(config, server_, config.name());
477:       RETURN_IF_NOT_OK_REF(listener_or_error.status());
478:       api_listener_ = std::move(listener_or_error.value());
479:       return true;
480:     } else {
481:       ENVOY_LOG(warn, "listener {} can not be added because currently only one ApiListener is "
482:                       "allowed, and it can only be added via bootstrap configuration");
483:       return false;
484:     }
485:   }
486: 
487:   // Address field is not required for internal listeners.
488:   if (!config.has_internal_listener() && !config.has_address()) {
489:     return absl::InvalidArgumentError(
490:         fmt::format("error adding listener named '{}': address is necessary", name));
491:   }
492: 
493:   auto it = error_state_tracker_.find(name);
494:   absl::StatusOr<bool> add_or_update_status;
495:   TRY_ASSERT_MAIN_THREAD {
496:     add_or_update_status = addOrUpdateListenerInternal(config, version_info, added_via_api, name);
497:   }
498:   END_TRY
499:   CATCH(const EnvoyException& e, { add_or_update_status = absl::InvalidArgumentError(e.what()); })
500:   if (!add_or_update_status.status().ok()) {
501:     if (it == error_state_tracker_.end()) {
502:       it = error_state_tracker_.emplace(name, std::make_unique<UpdateFailureState>()).first;
503:     }
504:     TimestampUtil::systemClockToTimestamp(server_.api().timeSource().systemTime(),
505:                                           *(it->second->mutable_last_update_attempt()));
506:     it->second->set_details(add_or_update_status.status().message());
507:     it->second->mutable_failed_configuration()->PackFrom(config);
508:   }
509:   return add_or_update_status;
510: }
