1002: void ListenerManagerImpl::stopListener(Network::ListenerConfig& listener,
1003:                                        const Network::ExtraShutdownListenerOptions& options,
1004:                                        std::function<void()> callback) {
1005:   const auto workers_pending_stop = std::make_shared<std::atomic<uint64_t>>(workers_.size());
1006:   for (const auto& worker : workers_) {
1007:     worker->stopListener(listener, options, [this, callback, workers_pending_stop]() {
1008:       if (--(*workers_pending_stop) == 0) {
1009:         server_.dispatcher().post(callback);
1010:       }
1011:     });
1012:   }
1013: }
